package com.dell.core.config;

import org.apache.felix.scr.annotations.*;
import org.osgi.framework.Constants;
import org.osgi.service.component.ComponentContext;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.Dictionary;

/**
 * The Class DellEMCConfiguration used to. configure application level
 * properties in Felix console.
 * 
 * @author
 */
@Component(immediate = true, label = "DellEMC  Configuration", description = "DellEMC Configuration", metatype = true)
@Properties({ @Property(name = Constants.SERVICE_DESCRIPTION, value = "DellEMC-Config"),
		@Property(name = Constants.SERVICE_VENDOR, value = "DellEMC") })
@Service(DellEmcConfigurations.class)

public class DellEmcConfigurations {
	/** The Constant LOG. */
	private static final Logger LOG = LoggerFactory.getLogger(DellEmcConfigurations.class);

	@Property(label = "Header Include Path Domain", value = "https://www.delltechnologies.com/content/emc/", description = "Configure .COM Header Site url")
	public static final String HEADER_INC_PATH = "header_inc_file";
	@Property(label = "Footer Include Path Domain", value = "https://www.delltechnologies.com/content/emc/", description = "Configure .COM Footer Site url")
	public static final String FOOTER_INC_PATH = "footer_inc_file";
	@Property(label = "PRM Sharepoint URL", value = "https://educate.one.dell.com/team/ContentDvt/", description = "PRM Sharepoint URL")
	public static final String PRM_SHAREPOINT_URL = "prm_sharepoint_url";
	@Property(label = "Dispatcher URL", value = "https://educationdev.dellemc.com", description = "Dispatcher URL")
	public static final String DISPATCHER_URL = "dispatcher_url";

	@SuppressWarnings("rawtypes")
	private static Dictionary properties = null;

	/**
	 * Activate.
	 * 
	 * @param componentContext
	 *            the component context
	 */
	@Activate
	protected final void activate(final ComponentContext componentContext) {
		LOG.info("DellEMC Configuration " + "Service Activated method called");
		try {
			properties = componentContext.getProperties();

		} catch (Exception e) {
			LOG.error("DellEMC Configuration ::" + "Error occured in activate method");
		}
	}

	/**
	 * Modified.
	 * 
	 * @param context
	 *            the context
	 */
	@Modified
	protected final void modified(final ComponentContext context) {
		LOG.info("DellEMC Configuration : configuration updated");
		try {
			properties = context.getProperties();

		} catch (Exception e) {
			LOG.error("Error while Updating configuration properties...");
		}
	}

	/**
	 * Deactivate.
	 * 
	 * @param context  
	 *            the context
	 */
	@Deactivate
	protected final void deactivate(final ComponentContext context) {
		LOG.info("DellEMC Configuration : deactivating service");
	}

	/**
	 * retrieve the property from the Component properties.
	 * 
	 * @param propertyName
	 *            the property name
	 * @return {@link Object}
	 */
	public static Object getPropertyValue(final String propertyName) {
		LOG.info("DellEMC Configuration : getPropertyValue ::" + propertyName);
		return properties.get(propertyName);

	}
}
